import zeep
from zeep import Client
from zeep.transports import Transport

# Define the WSDL URL for the third-party insurance service
wsdl_url = "https://example.com/insurance_service?wsdl"

# Create a new SOAP client using the zeep library
client = Client(wsdl=wsdl_url, transport=Transport())

# Define the policy lookup method on the client
policy_lookup = client.service.PolicyLookup

# Accept user input for policy number and customer name
policy_number = input("Enter policy number: ")
customer_name = input("Enter customer name: ")

# Build the SOAP XML body with the user-provided values
body = """
    <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:ins="http://example.com/insurance">
        <soapenv:Header/>
        <soapenv:Body>
            <ins:PolicyLookup>
                <ins:policyNumber>{policy_number}</ins:policyNumber>
                <ins:customerName>{customer_name}</ins:customerName>
            </ins:PolicyLookup>
        </soapenv:Body>
    </soapenv:Envelope>
""".format(policy_number=policy_number, customer_name=customer_name)

# Send the SOAP request to the third-party insurance service
response = client.service.PolicyLookup(body)

# Print the response from the service
print(response)